22	const basePremiumByType: Record<string, number> = {
23	  amulet: 60,
24	  sword: 100,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const PROCESSING_FEE = 5;
32	const BLOCK_OF_THREE_PREMIUM = 60;
33	const LOYALTY_DISCOUNT_RATE = 0.2;
34	const FIRST_INSURANCE_RATE = 0.1;
35	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	
40	function surchargeRateFor(item: Item): number {
41	  let rate = 0;
42	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
43	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
44	  return rate;
45	}
46	
47	function surchargeFor(item: Item): number {
48	  return basePremiumByType[item.type] * surchargeRateFor(item);
49	}
50	
51	function premiumForTypeBlock(type: string, count: number): number {
52	  if (count === 3) return BLOCK_OF_THREE_PREMIUM;
53	  return count * basePremiumByType[type];
54	}
55	
56	export function quote(
57	  customer: Customer,
58	  items: Item[],
59	  options: QuoteOptions = {},
60	): QuoteResult {
61	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
62	    counts[item.type] = (counts[item.type] ?? 0) + 1;
63	    return counts;
64	  }, {});
65	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
66	    (sum, [type, count]) => sum + premiumForTypeBlock(type, count),
67	    0,
68	  );
69	  const surcharges = items.reduce((sum, item) => sum + surchargeFor(item), 0);
70	  const basePremium = baseWithoutSurcharges + surcharges;
71	
72	  let premium = basePremium;
73	  if (customer.yearsWithMHPCO >= 2) premium -= baseWithoutSurcharges * LOYALTY_DISCOUNT_RATE;
74	  premium += baseWithoutSurcharges * FIRST_INSURANCE_RATE;
75	  if (options.followUp) premium -= baseWithoutSurcharges * FOLLOW_UP_DISCOUNT_RATE;
76	  premium = Math.ceil(premium + PROCESSING_FEE);
77	
78	  return { basePremium, premium, items };
79	}
