96	const insuranceValueByType: Record<string, number> = {
97	  sword: 1000,
98	  amulet: 600,
99	  staff: 800,
100	  potion: 400,
101	  rune: 250,
102	  moonstone: 250,
103	};
104	
105	const CAP_MULTIPLIER = 2;
106	const DEDUCTIBLE = 100;
107	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
108	const HALF_REIMBURSEMENT_RATE = 0.5;
109	
110	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
111	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
112	  const halfReimbursementApplies =
113	    (damagedItem?.enchantment ?? 0) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
114	  const reimbursed = halfReimbursementApplies
115	    ? damage.amount * HALF_REIMBURSEMENT_RATE
116	    : damage.amount;
117	  return reimbursed - DEDUCTIBLE;
118	}
119	
120	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
121	  const totalPayout = incident.damages.reduce(
122	    (total, damage) => total + payoutForDamage(damage, policy),
123	    0,
124	  );
125	  const payout = Math.floor(totalPayout);
126	  const cap =
127	    CAP_MULTIPLIER *
128	    policy.items.reduce((sum, item) => sum + insuranceValueByType[item.type], 0);
129	  return { payout, remainingCap: cap - payout };
130	}
